INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('quality_guidelines', '{"keySummary":{"tips":"Use the book title followed by the author name. Example: \"The Remains of the Day — Kazuo Ishiguro\". Keep it consistent for easy scanning."},"content":{"tips":"Write a review that helps someone decide whether to read this book. Include a brief summary, your reaction, key takeaways, and a rating."},"formatting":["Headings: separate Summary, Review, Key Takeaways, and Favorite Quotes sections","Bullet lists: key takeaways, themes, or discussion questions","Blockquotes: favorite passages and memorable quotes","Bold: highlight rating, page count, and publication year","Paragraphs: personal reaction and recommendation context"],"avoid":["Major plot spoilers without warning","Reviews without a clear recommendation or rating","Omitting the author name from the title","Copy-pasting publisher blurbs instead of personal review"]}', datetime('now'));
INSERT OR IGNORE INTO `settings` (`key`, `value`, `updated_at`) VALUES ('validation_limits', '{"keySummary":{"min":10,"max":200},"content":{"min":50,"max":10000},"sourceAi":{"min":1,"max":100}}', datetime('now'));

