INSERT OR IGNORE INTO `site_actions` (`id`, `name`, `slug`, `description`, `fields`, `settings`, `status`, `created_at`, `updated_at`) VALUES ('47819333-2113-4e90-8b8f-5c8f7ae47e45', 'Book Recommendation', 'book-recommendation', 'Recommend a book to add to the shelf', '[{"name":"name","type":"text","label":"Your Name","required":true,"placeholder":"Your name","maxLength":100},{"name":"email","type":"email","label":"Email","required":true,"placeholder":"you@example.com"},{"name":"book_title","type":"text","label":"Book Title","required":true,"placeholder":"Title of the book","maxLength":200},{"name":"author","type":"text","label":"Author","required":true,"placeholder":"Author name","maxLength":200},{"name":"why","type":"textarea","label":"Why do you recommend it?","required":true,"placeholder":"What makes this book worth reading?","maxLength":2000}]', '{"success_message":"Thanks for the recommendation! We''ll check it out and consider adding it to the shelf.","require_honeypot":true}', 'active', '2026-03-27T01:22:43.367Z', '2026-03-27T01:22:43.367Z');
